// Binary operators
let a = 1 + 2;
let b = 3 * 4 - 1;
let c = 10 % 3;
let d = 2 ** 8;

// Comparison
let e = a === b;
let f = a !== b;
let g = a < b;
let h = a >= b;

// Logical
let i = true && false;
let j = true || false;
let k = null ?? "default";

// Bitwise
let l = a & 0xFF;
let m = a | 0x0F;
let n = a ^ b;
let o = a << 2;
let p = a >> 1;
let q = a >>> 1;

// Unary
let r = -a;
let s = !true;
let t = ~0xFF;
let u = typeof a;
let v = void 0;

// Update
a++;
a--;
++a;
--a;

// Assignment
a += 1;
a -= 1;
a *= 2;
a /= 2;
a %= 3;
a **= 2;
a &&= true;
a ||= false;
a ??= 0;

// Ternary
let w = a > 0 ? "yes" : "no";

// Comma
let x = (1, 2, 3);
